public class Robot {
    int width, height, x, y, dir;
    int[] dx = {1, 0, -1, 0};
    int[] dy = {0, 1, 0, -1};

    public Robot(int width, int height) {
        this.width = width;
        this.height = height;
        x = 0;
        y = 0;
        dir = 0;
    }

    public void step(int num) {
        while (num-- > 0) {
            int nx = x + dx[dir];
            int ny = y + dy[dir];
            if (nx >= 0 && nx < width && ny >= 0 && ny < height) {
                x = nx;
                y = ny;
            } else {
                dir = (dir + 1) % 4;
                num++; // Retry the step
            }
        }
    }

    public int[] getPos() {
        return new int[]{x, y};
    }

    public String getDir() {
        switch(dir) {
            case 0: return "East";
            case 1: return "North";
            case 2: return "West";
            case 3: return "South";
        }
        return "";
    }
}
